code = """import json
import re
import pandas as pd

# Load review aggregates from storage variable
reviews = var_call_SVe2OFM2UMMXdKtkSEIO3mAP

# Load books info from file path (large result stored as file path)
books_path = var_call_xK3zLICZgSGPcfmbA8vGuoKD
with open(books_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

# DataFrames
df_rev = pd.DataFrame(reviews)
df_books = pd.DataFrame(books)

# helper to extract trailing integer
def extract_num(s):
    if not isinstance(s, str):
        return None
    m = re.search(r"(\d+)$", s)
    return int(m.group(1)) if m else None

df_rev['id_num'] = df_rev['purchase_id'].apply(extract_num)
df_books['id_num'] = df_books['book_id'].apply(extract_num)

# Convert numeric fields
try:
    df_rev['avg_rating'] = df_rev['avg_rating'].astype(float)
except Exception:
    df_rev['avg_rating'] = df_rev['avg_rating'].apply(lambda x: float(x) if x!='' else None)

try:
    df_rev['review_count'] = df_rev['review_count'].astype(int)
except Exception:
    df_rev['review_count'] = df_rev['review_count'].apply(lambda x: int(x) if x!='' else None)

# Merge on extracted numeric id
merged = pd.merge(df_books, df_rev, on='id_num', how='inner', suffixes=('_book','_rev'))

# Filter exact avg_rating == 5.0
matched = merged[merged['avg_rating']==5.0]

# Select and normalize fields
out_records = []
for _, row in matched.iterrows():
    rec = {
        'book_id': row.get('book_id',''),
        'purchase_id': row.get('purchase_id',''),
        'title': row.get('title',''),
        'author': row.get('author',''),
        'categories': row.get('categories',''),
        'details': row.get('details',''),
        'avg_rating': float(row.get('avg_rating')) if row.get('avg_rating') is not None else None,
        'review_count': int(row.get('review_count')) if row.get('review_count') is not None else None
    }
    out_records.append(rec)

# Print result in required format
print("__RESULT__:")
print(json.dumps(out_records))"""

